", "/* SVEM Command Center - Dark Professional Theme with Layout Fixes */

/* Global Reset and Dark Theme */
* {
 margin: 0;
 padding: 0;
 box-sizing: border-box;
}

html, body {
 margin: 0 !important;
 padding: 0 !important;
 background: #0F1117 !important;
 font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
 color: #E8E9ED;
 overflow: hidden;
 height: 100vh;
}

/* Remove any ServiceNow wrapper margins/padding */
#react-root,
.ui-page,
.ui-page-content {
 margin: 0 !important;
 padding: 0 !important;
 background: #0F1117 !important;
 height: 100vh;
 overflow: hidden;
}

/* Dashboard Container - Full viewport */
.dashboard-container {
 background: #0F1117;
 height: 100vh;
 display: flex;
 flex-direction: column;
 overflow: hidden;
}

/* Navigation Bar - 40px tall */
.dashboard-nav {
 height: 40px;
 background: #1A1D27;
 border-bottom: 1px solid #2A2D3A;
 display: flex;
 align-items: center;
 justify-content: space-between;
 padding: 0 16px;
 flex-shrink: 0;
}

.nav-left .app-title {
 font-size: 16px;
 font-weight: 700;
 color: #E8E9ED;
 margin: 0;
}

.nav-center {
 display: flex;
 gap: 24px;
}

.nav-link {
 color: #8B8D97;
 text-decoration: none;
 font-size: 12px;
 font-weight: 500;
 letter-spacing: 0.5px;
 transition: color 0.2s ease;
}

.nav-link:hover {
 color: #3B82F6;
}

.nav-right {
 display: flex;
 align-items: center;
 gap: 16px;
}

.analytics-btn {
 background: transparent;
 border: 1px solid #2A2D3A;
 color: #8B8D97;
 padding: 4px 12px;
 font-size: 12px;
 font-weight: 500;
 border-radius: 4px;
 cursor: pointer;
 transition: all 0.2s ease;
}

.analytics-btn:hover {
 border-color: #3B82F6;
 color: #3B82F6;
}

.language-switcher {
 display: flex;
 border: 1px solid #2A2D3A;
 border-radius: 4px;
 overflow: hidden;
}

.lang-btn {
 background: transparent;
 border: none;
 color: #8B8D97;
 padding: 4px 8px;
 font-size: 11px;
 font-weight: 500;
 cursor: pointer;
 transition: all 0.2s ease;
 border-right: 1px solid #2A2D3A;
}

.lang-btn:last-child {
 border-right: none;
}

.lang-btn:hover,
.lang-btn.active {
 background: #3B82F6;
 color: white;
}

/* Dashboard Content - Rest of viewport with 8px margin-top */
.dashboard-content {
 flex: 1;
 display: flex;
 flex-direction: column;
 padding: 8px 16px 16px 16px;
 gap: 8px;
 overflow: hidden;
}

/* KPI Cards Row - 60px tall */
.kpi-row {
 height: 60px;
 display: grid;
 grid-template-columns: 1fr 1fr 1fr 1fr;
 gap: 16px;
 flex-shrink: 0;
}

.kpi-card {
