 constructor() {
 this.baseUrl = '/api/now/table'
 this.headers = {
 Accept: 'application/json',
 'Content-Type': 'application/json',
 'X-UserToken': window.g_ck,
 }
 }

 async getJobs() {
 try {
 const params = new URLSearchParams({
 sysparm_display_value: 'all',
 sysparm_fields:
 'sys_id,job_number,po_number,customer,quantity_due,customer_due_date,ship_by_date,job_status,ship_status,priority,assigned_machine,current_operation,percent_complete,days_until_due',
 sysparm_limit: '100',
 })

 const response = await fetch(`${this.baseUrl}/x_1964226_svem_com_jobs?${params}`, {
 method: 'GET',
 headers: this.headers,
 })

 if (!response.ok) {
 throw new Error(`HTTP error! status: ${response.status}`)
 }

 const data = await response.json()
 return data.result || []
 } catch (error) {
 console.error('Error fetching jobs:', error)
 return []
 }
 }

 async getMachines() {
 try {
 const params = new URLSearchParams({
 sysparm_display_value: 'all',
 sysparm_fields:
 'sys_id,machine_name,machine_number,machine_type,status,current_job,current_operation,total_jobs_queued,uptime_percentage',
 sysparm_limit: '50',
 })

 const response = await fetch(`${this.baseUrl}/x_1964226_svem_com_machines?${params}`, {
 method: 'GET',
 headers: this.headers,
 })

 if (!response.ok) {
 throw new Error(`HTTP error! status: ${response.status}`)
 }

 const data = await response.json()
 return data.result || []
 } catch (error) {
 console.error('Error fetching machines:', error)
 return []
 }
 }

 async getOperations() {
 try {
 const params = new URLSearchParams({
 sysparm_display_value: 'all',
 sysparm_fields:
 'sys_id,job,sequence,work_center,description,op_status,preferred_machine,completed_by,started_date,completed_date,estimated_hours,actual_hours',
 sysparm_limit: '200',
 })

 const response = await fetch(`${this.baseUrl}/x_1964226_svem_com_operations?${params}`, {
 method: 'GET',
 headers: this.headers,
 })

 if (!response.ok) {
 throw new Error(`HTTP error! status: ${response.status}`)
 }

 const data = await response.json()
 return data.result || []
 } catch (error) {
 console.error('Error fetching operations:', error)
