 }
 }

 async getStaff() {
 try {
 const params = new URLSearchParams({
 sysparm_display_value: 'all',
 sysparm_fields:
 'sys_id,name,role,current_job,current_machine,current_operation,shift,status,jobs_completed_this_week',
 sysparm_limit: '50',
 })

 const response = await fetch(`${this.baseUrl}/x_1964226_svem_com_staff?${params}`, {
 method: 'GET',
 headers: this.headers,
 })

 if (!response.ok) {
 throw new Error(`HTTP error! status: ${response.status}`)
 }

 const data = await response.json()
 return data.result || []
 } catch (error) {
 console.error('Error fetching staff:', error)
 return []
 }
 }

 async getDeliveries() {
 try {
 const params = new URLSearchParams({
 sysparm_display_value: 'all',
 sysparm_fields:
 'sys_id,delivery_id,job,delivery_type,delivery_status,carrier,tracking_number,ship_by_date,need_by_date,quantity_due',
 sysparm_limit: '100',
 })

 const response = await fetch(`${this.baseUrl}/x_1964226_svem_com_deliveries?${params}`, {
 method: 'GET',
 headers: this.headers,
 })

 if (!response.ok) {
 throw new Error(`HTTP error! status: ${response.status}`)
 }

 const data = await response.json()
 return data.result || []
 } catch (error) {
 console.error('Error fetching deliveries:', error)
 return []
 }
 }

 async updateJob(jobId, updates) {
 try {
 const response = await fetch(`${this.baseUrl}/x_1964226_svem_com_jobs/${jobId}`, {
 method: 'PATCH',
 headers: this.headers,
 body: JSON.stringify(updates),
 })

 if (!response.ok) {
 throw new Error(`HTTP error! status: ${response.status}`)
 }

 return await response.json()
 } catch (error) {
 console.error('Error updating job:', error)
 throw error
 }
 }

 async completeOperation(operationId) {
 try {
 const response = await fetch(`${this.baseUrl}/x_1964226_svem_com_operations/${operationId}`, {
 method: 'PATCH',
 headers: this.headers,
 body: JSON.stringify({
 op_status: 'complete',
 completed_date: new Date().toISOString(),
 }),
 })

 if (!response.ok) {
 throw new Error(`HTTP error! status: ${response.status}`)
 }

 return await response.json()
 } catch (error) {
 console.error('Error completing operation:', error)
 throw error
 }
 }

 async quickCompleteOperation(jobNumber, workCenter) {
 try {
 // First find the job
 const jobParams = new URLSearchParams({
 sysparm_query: `job_number=${jobNumber}`,
 sysparm_display_value: 'all',
 sysparm_limit: '1',
 })

 const jobResponse = await fetch(`${this.baseUrl}/x_1964226_svem_com_jobs?${jobParams}`, {
 method: 'GET',
 headers: this.headers,
 })

 if (!jobResponse.ok) {
 throw new Error('Job not found')
 }

 const jobData = await jobResponse.json()
 if (!jobData.result || jobData.result.length === 0) {
 throw new Error('Job not found')
 }

 const job = jobData.result[0]
 const jobId = typeof job.sys_id === 'object' ? job.sys_id.value : job.sys_id

 // Find the operation
 const opParams = new URLSearchParams({
 sysparm_query: `job=${jobId}^work_center=${workCenter}^op_status=in_progress`,
 sysparm_display_value: 'all',
 sysparm_limit: '1',
 })

 const opResponse = await fetch(`${this.baseUrl}/x_1964226_svem_com_operations?${opParams}`, {
 method: 'GET',
 headers: this.headers,
 })

 if (!opResponse.ok) {
 throw new Error('Operation not found')
 }

 const opData = await opResponse.json()
 if (!opData.result || opData.result.length === 0) {
 throw new Error('No in-progress operation found')
 }

 const operation = opData.result[0]
 const operationId = typeof operation.sys_id === 'object' ? operation.sys_id.value : operation.sys_id

 // Complete the operation
 return await this.completeOperation(operationId)
 } catch (error) {
 console.error('Error with quick complete:', error)
 throw error
 }
 }
}

export const svemService = new SvemService();
", "import React from 'react'

export default function KpiCards({ jobs, machines, translations }) {
 const t = translations

 const getActiveJobs = () => {
 return jobs.filter(job => {
 const status = typeof job.job_status === 'object' ? job.job_status.value : job.job_status
 return status === 'in_progress'
 }).length
 }

 const getPastDueJobs = () => {
 const today = new Date()
 today.setHours(0, 0, 0, 0)

 return jobs.filter(job => {
 const status = typeof job.job_status === 'object' ? job.job_status.value : job.job_status
 const shipByDate = new Date(typeof job.ship_by_date === 'object' ? job.ship_by_date.value : job.ship_by_date)

 return shipByDate < today && status !== 'shipped' && status !== 'complete'
 }).length
 }

 const getRunningMachines = () => {
 const runningCount = machines.filter(machine => {
 const status = typeof machine.status === 'object' ? machine.status.value : machine.status
 return status === 'running'
 }).length
 return `${runningCount}/16`
 }

 const getShippingThisWeek = () => {
 const today = new Date()
 const startOfWeek = new Date(today.getFullYear(), today.getMonth(), today.getDate() - today.getDay())
 const endOfWeek = new Date(today.getFullYear(), today.getMonth(), today.getDate() - today.getDay() + 6)

 return jobs.filter(job => {
 const shipByDate = new Date(typeof job.ship_by_date === 'object' ? job.ship_by_date.value : job.ship_by_date)
 return shipByDate >= startOfWeek && shipByDate <= endOfWeek
 }).length
 }

 const activeJobs = getActiveJobs()
 const pastDueJobs = getPastDueJobs()
 const runningMachines = getRunningMachines()
 const shippingThisWeek = getShippingThisWeek()

 return (
 <>
 <div className="kpi-card">
 <div className="kpi-value">{activeJobs}</div>
 <div className="kpi-label">{t('ACTIVE JOBS')}</div>
 </div>

 <div className={`kpi-card ${pastDueJobs > 0 ? 'past-due' : ''}`}>
 <div className="kpi-value">{pastDueJobs}</div>
 <div className="kpi-label">{t('PAST DUE')}</div>
 </div>

 <div className="kpi-card machines-running">
 <div className="kpi-value">{runningMachines}</div>
 <div className="kpi-label">{t('MACHINES RUNNING')}</div>
 </div>

 <div className="kpi-card">
 <div className="kpi-value">{shippingThisWeek}</div>
 <div className="kpi-label">{t('SHIPPING THIS WEEK')}</div>
 </div>
 </>
 )
