export default function JobTracker({ jobs, translations }) {
 const t = translations

 const extractValue = (field) => {
 if (!field) return ''
 return typeof field === 'object' ? field.display_value : field
 }

 const formatDate = (date) => {
 if (!date) return ''
 const dateValue = typeof date === 'object' ? date.value : date
 return new Date(dateValue).toLocaleDateString('en-US', { month: '2-digit', day: '2-digit' })
 }

 const getStatusDot = (status) => {
 const statusMap = {
 'not_started': 'idle',
 'in_progress': 'running', 
 'on_hold': 'maintenance',
 'complete': 'running',
 'shipped': 'running'
 }
 return statusMap[status] || 'idle'
 }

 const getPriorityDot = (priority) => {
 return priority || 'medium'
 }

 const openJobs = jobs.filter(job => {
 const status = typeof job.job_status === 'object' ? job.job_status.value : job.job_status
 return status !== 'shipped' && status !== 'complete'
 }).sort((a, b) => {
 const dateA = new Date(typeof a.ship_by_date === 'object' ? a.ship_by_date.value : a.ship_by_date)
 const dateB = new Date(typeof b.ship_by_date === 'object' ? b.ship_by_date.value : b.ship_by_date)
 return dateA - dateB
 })

