export default function MachineGrid({ machines, jobs, translations }) {
 const t = translations

 const extractValue = (field) => {
 if (!field) return ''
 return typeof field === 'object' ? field.display_value : field
 }

 const getJobNumber = (machineCurrentJob) => {
 if (!machineCurrentJob) return ''

 const jobId = typeof machineCurrentJob === 'object' ? machineCurrentJob.value : machineCurrentJob
 const job = jobs.find(j => {
 const sysId = typeof j.sys_id === 'object' ? j.sys_id.value : j.sys_id
 return sysId === jobId
 })

 return job ? extractValue(job.job_number) : ''
 }

 // Sort machines by name to ensure consistent 4x4 grid layout
 const sortedMachines = [...machines].sort((a, b) => {
 const nameA = extractValue(a.machine_name)
 const nameB = extractValue(b.machine_name)
 return nameA.localeCompare(nameB)
 })

 const runningCount = machines.filter(m => extractValue(m.status) === 'running').length
 const utilizationPercent = Math.round((runningCount / 16) * 100)

 return (
 <div className="machine-grid-panel">
 <div className="panel-header">
 <a 
 href="/x_1964226_svem_com_machines_list.do" 
 className="panel-title"
 target="_blank"
 >
 Shop Floor ({runningCount}/16 • {utilizationPercent}%)
 </a>
 </div>

 <div className="machine-grid">
 {sortedMachines.map(machine => {
 const sysId = typeof machine.sys_id === 'object' ? machine.sys_id.value : machine.sys_id
 const status = extractValue(machine.status)
 const machineName = extractValue(machine.machine_name)
 const currentJob = getJobNumber(machine.current_job)

 return (
 <a 
 key={sysId}
 href={`/x_1964226_svem_com_machines.do?sys_id=${sysId}`}
 target="_blank"
 className={`machine-tile ${status}`}
 title={`${machineName} - ${status.toUpperCase()}${currentJob ? ` - Job: ${currentJob}` : ''}`}
 >
 <div className="machine-header">
 <div className="machine-name">{machineName}</div>
 <span className={`status-dot ${status}`}></span>
 </div>
 <div className="machine-job">
 {currentJob || 'IDLE'}
 </div>
 </a>
 )
 })}
 </div>
 </div>
 )
