export default function OpsKanban({ operations, jobs, translations }) {
 const t = translations

 const workCenters = [
 { key: 'review', label: 'REV' },
 { key: 'saw', label: 'SAW' },
 { key: 'programming', label: 'PGM' },
 { key: 'vmill', label: 'MILL' },
 { key: 'deburr', label: 'DBR' },
 { key: 'qc_pre', label: 'QC1' },
 { key: 'outsource', label: 'OSP' },
 { key: 'qc_final', label: 'QC2' },
 { key: 'pack_ship', label: 'P&S' }
 ]

 const extractValue = (field) => {
 if (!field) return ''
 return typeof field === 'object' ? field.display_value : field
 }

 const getActiveOperations = () => {
 return operations.filter(op => {
 const status = extractValue(op.op_status)
 return status === 'pending' || status === 'in_progress'
 })
 }

 const getOperationsByWorkCenter = (workCenterKey) => {
 const activeOps = getActiveOperations()
 return activeOps.filter(op => extractValue(op.work_center) === workCenterKey)
 }

 const getJobForOperation = (operation) => {
 const jobId = typeof operation.job === 'object' ? operation.job.value : operation.job
 return jobs.find(j => {
 const sysId = typeof j.sys_id === 'object' ? j.sys_id.value : j.sys_id
 return sysId === jobId
 })
 }

 const getPriorityClass = (job) => {
 if (!job) return 'medium'
 const priority = extractValue(job.priority)
 return priority
 }

 return (
 <div className="ops-kanban">
 <div className="panel-header">
 <a 
 href="/x_1964226_svem_com_operations_list.do" 
 className="panel-title"
 target="_blank"
 >
 Operations Pipeline
 </a>
 </div>

 <div className="kanban-columns">
 {workCenters.map(workCenter => {
 const operations = getOperationsByWorkCenter(workCenter.key)
 const isBottleneck = operations.length >= 3

 return (
 <div 
 key={workCenter.key} 
 className={`kanban-column ${operations.length > 0 ? 'has-jobs' : ''} ${isBottleneck ? 'bottleneck' : ''}`}
 >
 <div className="column-label">{workCenter.label}</div>

 <div className="job-cards">
 {operations.map(operation => {
 const job = getJobForOperation(operation)
 const operationId = typeof operation.sys_id === 'object' ? 
 operation.sys_id.value : operation.sys_id
 const priorityClass = getPriorityClass(job)
 const jobSysId = job ? (typeof job.sys_id === 'object' ? job.sys_id.value : job.sys_id) : null

 return (
 <a
 key={operationId}
 href={jobSysId ? `/x_1964226_svem_com_jobs.do?sys_id=${jobSysId}` : '#'}
 target="_blank"
 className={`job-card priority-${priorityClass}`}
 title={job ? extractValue(job.job_number) : 'Unknown Job'}
 >
 <div className="card-job">
 {job ? extractValue(job.job_number) : 'N/A'}
 </div>
 </a>
 )
 })}
 </div>
 </div>
 )
 })}
 </div>
