export default function StaffStrip({ staff, translations }) {
 const t = translations

 const extractValue = (field) => {
 if (!field) return ''
 return typeof field === 'object' ? field.display_value : field
 }

 const getFirstName = (fullName) => {
 if (!fullName || fullName === 'N/A') return '?'
 return fullName.split(' ')[0]
 }

 const getInitial = (name) => {
 return name ? name.charAt(0).toUpperCase() : '?'
 }

 const getRoleLabel = (role) => {
 const labels = {
 'programmer': 'PROG',
 'operator': 'OPR',
 'setup_operator': 'SETUP',
 'qc_technician': 'QC',
 'deburr_operator': 'DBR',
 'material_handler': 'MAT',
 'driver': 'DRV',
 'shipping_technician': 'SHIP'
 }
 return labels[role] || role.toUpperCase()
 }

 // Group staff by role categories
 const staffByCategory = staff.reduce((groups, member) => {
 const role = extractValue(member.role)
 let category = 'OTHER'

 if (role === 'operator') category = 'OPS'
 else if (role === 'setup_operator') category = 'SETUP'
 else if (role === 'qc_technician') category = 'QC'

 if (!groups[category]) groups[category] = []
 groups[category].push(member)
 return groups
 }, {})

 const categories = ['OPS', 'SETUP', 'QC', 'OTHER']

 return (
 <div className="staff-groups">
 {categories.map((category, index) => {
 const members = staffByCategory[category] || []

 return (
 <React.Fragment key={category}>
 {index > 0 && <div className="group-divider"></div>}

 <div className="staff-group">
 <div className="group-label">{category}</div>

 {members.map(member => {
 const sysId = typeof member.sys_id === 'object' ? member.sys_id.value : member.sys_id
 const name = extractValue(member.name)
 const role = extractValue(member.role)
 const status = extractValue(member.status)
 const firstName = getFirstName(name)
 const initial = getInitial(name)

 return (
 <a 
 key={sysId}
 href={`/x_1964226_svem_com_staff.do?sys_id=${sysId}`}
 target="_blank"
 className="staff-avatar"
 title={`${name} - ${status.toUpperCase()}`}
 >
 <div className="avatar-circle">
 {initial}
 <span className={`staff-status-dot ${status}`}></span>
 </div>
 <div className="staff-name">{firstName}</div>
 <div className="staff-role">{getRoleLabel(role)}</div>
 </a>
 )
 })}
 </div>
 </React.Fragment>
 )
 })}
 </div>
 )
