export default function Analytics({ jobs, machines, operations, onClose, translations }) {
 const t = translations
 const [dateRange, setDateRange] = useState('4weeks')

 const extractValue = (field) => {
 if (!field) return ''
 return typeof field === 'object' ? field.display_value : field
 }

 // Chart 1: Machine Utilization
 const getMachineUtilization = () => {
 return machines.map(machine => {
 const name = extractValue(machine.machine_name)
 const uptime = Math.random() * 100 // Placeholder - would be calculated from actual data
 let color = '#EF4444' // Red below 40%
 if (uptime >= 70) color = '#22C55E' // Green above 70%
 else if (uptime >= 40) color = '#F59E0B' // Amber 40-70%

 return { name, uptime, color }
 }).sort((a, b) => b.uptime - a.uptime)
 }

 // Chart 2: Jobs by Status
 const getJobsByStatus = () => {
 const statusCounts = {}
 jobs.forEach(job => {
 const status = extractValue(job.job_status) || 'unknown'
 statusCounts[status] = (statusCounts[status] || 0) + 1
 })

 const total = Object.values(statusCounts).reduce((sum, count) => sum + count, 0)
 return { statusCounts, total }
 }

 // Chart 3: Average Hours per Work Center
 const getWorkCenterHours = () => {
 const workCenters = ['review', 'saw', 'programming', 'vmill', 'deburr', 'qc_pre', 'outsource', 'qc_final', 'pack_ship']

 return workCenters.map(wc => {
 const avgHours = 2 + Math.random() * 6 // Placeholder calculation
 return {
 workCenter: wc.toUpperCase(),
 avgHours,
 isHighest: false
 }
 }).map((wc, index, arr) => {
 const maxHours = Math.max(...arr.map(w => w.avgHours))
 return { ...wc, isHighest: wc.avgHours === maxHours }
 })
 }

 // Chart 4: Daily Jobs Completed (Mock Data)
 const getDailyJobsCompleted = () => {
 const days = []
 for (let i = 27; i >= 0; i--) {
 const date = new Date()
 date.setDate(date.getDate() - i)
 days.push({
 date: date.toISOString().split('T')[0],
 completed: Math.floor(2 + Math.random() * 8)
 })
 }
 return days
 }

 // Chart 5: On-Time Delivery Rate
 const getOnTimeDeliveryRate = () => {
 const rate = 85 + Math.random() * 12 // Placeholder: 85-97%
 let color = '#EF4444' // Red below 75%
 if (rate >= 90) color = '#22C55E' // Green above 90%
 else if (rate >= 75) color = '#F59E0B' // Amber 75-90%

 return { rate: Math.round(rate), color }
 }

 const machineUtilization = getMachineUtilization()
 const jobsByStatus = getJobsByStatus()
 const workCenterHours = getWorkCenterHours()
 const dailyJobs = getDailyJobsCompleted()
 const onTimeRate = getOnTimeDeliveryRate()

 return (
 <div className="analytics-overlay" onClick={onClose}>
 <div className="analytics-panel" onClick={e => e.stopPropagation()}>
 <div className="analytics-header">
 <h3>{t('Analytics Dashboard')}</h3>
 <div className="analytics-controls">
 <select 
 value={dateRange} 
 onChange={(e) => setDateRange(e.target.value)}
 className="date-range-picker"
 >
 <option value="1week">Last Week</option>
 <option value="4weeks">Last 4 Weeks</option>
 <option value="3months">Last 3 Months</option>
 </select>
 <button className="analytics-close" onClick={onClose}>×</button>
 </div>
 </div>

 <div className="analytics-content">
 <div className="chart-grid">
 {/* Chart 1: Machine Utilization */}
 <div className="chart-card">
 <h4>Machine Utilization</h4>
 <div className="horizontal-bar-chart">
 {machineUtilization.map(machine => (
 <div key={machine.name} className="bar-row">
 <div className="bar-label">{machine.name}</div>
 <div className="bar-container">
 <div 
 className="bar-fill"
 style={{ 
 width: `${machine.uptime}%`,
 backgroundColor: machine.color
 }}
 ></div>
 </div>
 <div className="bar-value">{Math.round(machine.uptime)}%</div>
 </div>
 ))}
 </div>
 </div>

 {/* Chart 2: Jobs by Status */}
 <div className="chart-card">
 <h4>Jobs by Status</h4>
 <div className="donut-chart">
 <div className="donut-center">
 <div className="donut-total">{jobsByStatus.total}</div>
 <div className="donut-label">TOTAL JOBS</div>
 </div>
 <div className="donut-segments">
 {Object.entries(jobsByStatus.statusCounts).map(([status, count]) => (
 <div key={status} className="status-segment">
 <span className={`status-dot ${status}`}></span>
 <span className="segment-label">{status.toUpperCase()}</span>
 <span className="segment-count">{count}</span>
 </div>
 ))}
 </div>
 </div>
 </div>

 {/* Chart 3: Work Center Hours */}
 <div className="chart-card">
 <h4>Avg Hours per Work Center</h4>
 <div className="vertical-bar-chart">
 {workCenterHours.map(wc => (
 <div key={wc.workCenter} className="vertical-bar">
 <div className="v-bar-container">
 <div 
 className="v-bar-fill"
 style={{ 
 height: `${(wc.avgHours / 8) * 100}%`,
 backgroundColor: wc.isHighest ? '#EF4444' : '#3B82F6'
 }}
 ></div>
 </div>
 <div className="v-bar-label">{wc.workCenter}</div>
 <div className="v-bar-value">{wc.avgHours.toFixed(1)}h</div>
 </div>
 ))}
 </div>
 </div>

 {/* Chart 4: Daily Production Trend */}
 <div className="chart-card">
 <h4>Daily Jobs Completed</h4>
 <div className="line-chart">
 <svg width="100%" height="200" viewBox="0 0 400 200">
 <defs>
 <linearGradient id="areaGradient" x1="0%" y1="0%" x2="0%" y2="100%">
 <stop offset="0%" style={{stopColor: '#3B82F6', stopOpacity: 0.3}} />
 <stop offset="100%" style={{stopColor: '#3B82F6', stopOpacity: 0}} />
 </linearGradient>
 </defs>

 {/* Generate path for line chart */}
 {(() => {
 const points = dailyJobs.map((day, index) => {
 const x = (index / (dailyJobs.length - 1)) * 380 + 10
 const y = 180 - ((day.completed / 10) * 160)
