 cy={y} 
 r="3" 
 fill="#3B82F6"
 />
 )
 })}
 </>
 )
 })()}
 </svg>
 </div>
 </div>

 {/* Chart 5: On-Time Delivery Rate */}
 <div className="chart-card delivery-rate-card">
