 <div className="nav-center">
 <a href="/x_1964226_svem_com_jobs_list.do" className="nav-link">{t('JOBS') || 'JOBS'}</a>
 <a href="/x_1964226_svem_com_operations_list.do" className="nav-link">{t('OPERATIONS') || 'OPERATIONS'}</a>
 <a href="/x_1964226_svem_com_machines_list.do" className="nav-link">{t('MACHINES') || 'MACHINES'}</a>
 <a href="/x_1964226_svem_com_staff_list.do" className="nav-link">{t('STAFF') || 'STAFF'}</a>
 <a href="/x_1964226_svem_com_deliveries_list.do" className="nav-link">{t('DELIVERIES') || 'DELIVERIES'}</a>
 </div>
 <div className="nav-right">
 <button className="analytics-btn" onClick={() => setShowAnalytics(true)}>
 ANALYTICS
 </button>
 <div className="language-switcher">
 {['en', 'es', 'zh', 'vi', 'tl'].map(lang => (
 <button
 key={lang}
 className={`lang-btn ${currentLanguage === lang ? 'active' : ''}`}
 onClick={() => handleLanguageChange(lang)}
 >
 {lang === 'en' ? 'EN' : lang === 'es' ? 'ES' : lang === 'zh' ? '中' : lang === 'vi' ? 'VI' : 'TL'}
 </button>
 ))}
 </div>
 </div>
 </nav>

 <div className="dashboard-content">
 <div className="kpi-row">
 <KpiCards jobs={data.jobs} machines={data.machines} translations={t} />
 </div>

 <div className="main-row">
 <div className="panel job-tracker-panel">
 <JobTracker jobs={data.jobs} onJobClick={handleJobClick} translations={t} />
 </div>
 <div className="panel machine-grid-panel">
 <MachineGrid machines={data.machines} jobs={data.jobs} onMachineClick={handleMachineClick} translations={t} />
 </div>
 <div className="panel ops-pipeline-panel">
 <OpsKanban operations={data.operations} jobs={data.jobs} onJobClick={handleJobClick} translations={t} />
 </div>
 </div>

 <div className="staff-row">
 <StaffStrip staff={data.staff} onStaffClick={handleStaffClick} translations={t} />
 </div>
 </div>

 {showAnalytics && (
 <Analytics jobs={data.jobs} machines={data.machines} operations={data.operations} onClose={() => setShowAnalytics(false)} translations={t} />
 )}
 </div>
 );
};

